import{_ as e,c as t,o as r,a2 as o}from"./chunks/framework.DdOM6S6U.js";const m=JSON.parse('{"title":"Repositories","description":"","frontmatter":{"sidebarPos":4,"sidebarTitle":"Repositories"},"headers":[],"relativePath":"system-reference/repositories.md","filePath":"system-reference/repositories.md","lastUpdated":null}'),d={name:"system-reference/repositories.md"},a=o(`<h1 id="repositories" tabindex="-1">Repositories <a class="header-anchor" href="#repositories" aria-label="Permalink to &quot;Repositories&quot;">​</a></h1><p>Repositories are the single data access layer. All create/update/delete logic must pass through repository methods. Controllers never access Eloquent models directly.</p><h2 id="controller-usage" tabindex="-1">Controller Usage <a class="header-anchor" href="#controller-usage" aria-label="Permalink to &quot;Controller Usage&quot;">​</a></h2><div class="language-php vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">php</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// From PanelController (base for all module controllers)</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">$this</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-&gt;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">repository  </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// Resolved by route name via Finder</span></span></code></pre></div><h2 id="create-lifecycle" tabindex="-1">Create Lifecycle <a class="header-anchor" href="#create-lifecycle" aria-label="Permalink to &quot;Create Lifecycle&quot;">​</a></h2><p>Order of execution in <code>Repository::create()</code>:</p><ol><li><code>prepareFieldsBeforeCreate($fields)</code></li><li><code>model-&gt;create($fields)</code> — creates DB record</li><li><code>beforeSave($object, $original_fields)</code></li><li><code>prepareFieldsBeforeSave($object, $fields)</code></li><li><code>$object-&gt;save()</code></li><li><code>afterSave($object, $fields)</code></li><li><code>dispatchEvent($object, &#39;create&#39;)</code></li></ol><h2 id="method-transformers" tabindex="-1">Method Transformers <a class="header-anchor" href="#method-transformers" aria-label="Permalink to &quot;Method Transformers&quot;">​</a></h2><p>Override these in the repository or via transformer classes to intercept lifecycle:</p><table><thead><tr><th>Hook</th><th>When</th></tr></thead><tbody><tr><td><code>prepareFieldsBeforeCreate</code></td><td>Before DB insert</td></tr><tr><td><code>beforeSave</code></td><td>After create, before save</td></tr><tr><td><code>prepareFieldsBeforeSave</code></td><td>Before save (can modify fields)</td></tr><tr><td><code>afterSave</code></td><td>After save</td></tr><tr><td><code>beforeCreate</code> / <code>afterCreate</code></td><td>Wrapped around create</td></tr><tr><td><code>beforeUpdate</code> / <code>afterUpdate</code></td><td>Wrapped around update</td></tr></tbody></table><h2 id="logic-traits" tabindex="-1">Logic Traits <a class="header-anchor" href="#logic-traits" aria-label="Permalink to &quot;Logic Traits&quot;">​</a></h2><p><code>Repository</code> uses these traits from <code>Repositories/Logic/</code>:</p><table><thead><tr><th>Trait</th><th>Purpose</th></tr></thead><tbody><tr><td>QueryBuilder</td><td>Query building, filters</td></tr><tr><td>MethodTransformers</td><td>Lifecycle hooks</td></tr><tr><td>Relationships</td><td>Relationship handling</td></tr><tr><td>RelationshipHelpers</td><td>Relationship utilities</td></tr><tr><td>Schema</td><td>Schema handling, chunkInputs</td></tr><tr><td>InspectTraits</td><td>Trait inspection</td></tr><tr><td>CountBuilders</td><td>Count queries</td></tr><tr><td>Dates</td><td>Date handling</td></tr><tr><td>DispatchEvents</td><td>Event dispatching</td></tr><tr><td>CollationSelector</td><td>Collation selection</td></tr><tr><td>CacheableTrait</td><td>Caching</td></tr><tr><td>TouchableEloquentModel</td><td>Touch timestamps</td></tr></tbody></table><h2 id="reserved-fields" tabindex="-1">Reserved Fields <a class="header-anchor" href="#reserved-fields" aria-label="Permalink to &quot;Reserved Fields&quot;">​</a></h2><p>Fields in <code>getReservedFields()</code> are excluded from <code>model-&gt;create()</code>. Override <code>$ignoreFieldsBeforeSave</code> to add more.</p><h2 id="fields-groups" tabindex="-1">Fields Groups <a class="header-anchor" href="#fields-groups" aria-label="Permalink to &quot;Fields Groups&quot;">​</a></h2><p>Use <code>$fieldsGroups</code> to group form fields. Schema is chunked by groups for <code>prepareFieldsBeforeCreate</code> / <code>prepareFieldsBeforeSave</code>.</p>`,17),s=[a];function i(l,c,n,h,p,f){return r(),t("div",null,s)}const b=e(d,[["render",i]]);export{m as __pageData,b as default};
